module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

localparam IDLE = 2'b00;
localparam LOAD = 2'b01;
localparam CALCULATE = 2'b10;
localparam OUTPUT = 2'b11;

reg [1:0] state, next_state;
reg [3:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
wire [15:0] temp[7:0];
reg [15:0] sum[5:0];
reg [15:0] mul_out_reg;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case(state)
        IDLE: begin
            if(~mul_en_in) begin
                next_state = IDLE;
            end else begin
                next_state = LOAD;
            end
        end
        LOAD: begin
            next_state = CALCULATE;
        end
        CALCULATE: begin
            next_state = OUTPUT;
        end
        OUTPUT: begin
            next_state = IDLE;
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_a_reg <= 8'd0;
        mul_b_reg <= 8'd0;
        mul_en_out_reg <= 4'd0;
    end else begin
        case(state)
            IDLE: begin
                if(mul_en_in) begin
                    mul_a_reg <= mul_a;
                    mul_b_reg <= mul_b;
                end else begin
                    mul_a_reg <= 8'd0;
                    mul_b_reg <= 8'd0;
                end
            end
            LOAD: begin

            end
            CALCULATE: begin
                mul_en_out_reg <= {3'd0, mul_en_in};
            end
            OUTPUT: begin

            end
            default: begin

            end
        endcase
    end
end

genvar i;
generate
    for(i = 0; i < 8; i = i + 1) begin : pp_gen
        assign temp[i][15:0] = (mul_b_reg[i]) ? {{8{1'b0}}, mul_a_reg} << i : 16'd0;
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum[0] <= 16'd0;
        sum[1] <= 16'd0;
        sum[2] <= 16'd0;
        sum[3] <= 16'd0;
        sum[4] <= 16'd0;
        sum[5] <= 16'd0;
    end else begin
        case(state)
            IDLE: begin

            end
            LOAD: begin

            end
            CALCULATE: begin
                sum[0] <= temp[0];
                sum[1] <= temp[1] + temp[2];
                sum[2] <= temp[3] + temp[4];
                sum[3] <= temp[5] + temp[6];
                sum[4] <= temp[7];
                sum[5] <= 16'd0;
            end
            OUTPUT: begin

            end
            default: begin

            end
        endcase
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out_reg <= 16'd0;
    end else begin
        case(state)
            IDLE: begin

            end
            LOAD: begin

            end
            CALCULATE: begin

            end
            OUTPUT: begin
                mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5];
            end
            default: begin

            end
        endcase
    end
end

assign mul_out = (mul_en_out_reg[3]) ? mul_out_reg : 16'd0;

assign mul_en_out = mul_en_out_reg[3];
endmodule
